#include<bits/stdc++.h>
using namespace std;
long long n,a[100005];
long long ans=0;
int main()
{
    cin>>n;
    for(int i=1;i<=n;i++) cin>>a[i];
    for(int i=2;i<=n;i++)
    {
    	if(a[i]>a[i-1])
		{
    		ans+=a[i]-a[i-1];
		}
	}
    cout<<a[1]+ans;
    return 0;
}
